import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class SpeakerButton extends StatelessWidget { final bool isOn; final VoidCallback onToggle; const SpeakerButton({super.key, required this.isOn, required this.onToggle}); @override Widget build(BuildContext context) => Column(mainAxisSize: MainAxisSize.min, children: [Material(color: isOn ? AppTheme.primaryColor.withOpacity(0.15) : Colors.white.withOpacity(0.1), shape: const CircleBorder(), child: InkWell(onTap: onToggle, customBorder: const CircleBorder(), child: Padding(padding: const EdgeInsets.all(14), child: Icon(isOn ? Icons.volume_up_rounded : Icons.volume_down_rounded, color: isOn ? AppTheme.primaryColor : Colors.white, size: 26)))), const SizedBox(height: 6), Text('Speaker', style: const TextStyle(color: AppTheme.darkSubtext, fontSize: 11))]); }